  DEN: { coach: 'Sean Payton', scheme: '3-4',          storyline: 'The roster is really, really good. Anticipate departures at offensive line and corner, and otherwise have a chill day in the war room.', urgency: 'OT, CB' },
  DET: { coach: 'Dan Campbell', scheme: '4-3',         storyline: 'Return the offensive line to full strength. Address CB and edge rusher with what remains.', urgency: 'OT, CB' },
  GB:  { coach: 'Matt LaFleur', scheme: '3-4',         storyline: 'Defensive line is the most obvious need, but offensive line might need help just as badly. And please draft a corner!', urgency: 'DL, OT' },
  HOU: { coach: 'DeMeco Ryans', scheme: '4-3',         storyline: 'Keep investing in the offensive line, then take some high-impact gambles.', urgency: 'OT, DL' },
  IND: { coach: 'Shane Steichen', scheme: '4-3',       storyline: 'Use Day 3 picks to trade up and fill immediate gaps at linebacker, safety and edge rusher. If a tackle or receiver falls, go for it.', urgency: 'LB, S' },
  JAX: { coach: 'Liam Coen', scheme: '4-3',            storyline: 'Stay, pick, develop, prosper. The only must-gets are defensive tackle and linebacker.', urgency: 'DT, LB' },
  KC:  { coach: 'Andy Reid', scheme: '4-3',            storyline: 'Leave the draft with enough defensive talent to start the new era of Super Bowl contention under Mahomes. Sounds easy enough!', urgency: 'CB, EDGE' },
  LV:  { coach: 'Klint Kubiak', scheme: '3-4',         storyline: 'Support presumed No. 1 pick Fernando Mendoza at QB with a big-bodied receiver (and, please, an offensive lineman, pretty please). Find a 600-plus snap player at defensive tackle and a potential starting corner.', urgency: 'QB, WR' },
  LAC: { coach: 'Jim Harbaugh', scheme: '3-4',         storyline: 'Draft a good guard, prepare for defensive departures and age regression, and then draft another guard.', urgency: 'IOL, DL' },
  LAR: { coach: 'Sean McVay', scheme: '3-4',           storyline: 'Push for the Super Bowl. Draft pro-ready players, ideally at tackle, wide receiver and linebacker. Trade up!', urgency: 'OT, WR' },
  MIA: { coach: 'Jeff Hafley', scheme: '4-3',          storyline: 'Make a lot of picks, trade down for more picks and trade down for 2027 picks to prepare for potentially trading up for a QB. Draft risky players.', urgency: 'WR, CB' },
  MIN: { coach: 'Kevin O\'Connell', scheme: '3-4',     storyline: 'Just take a lot of good players. You\'ll need them. (Don\'t trade up for a shiny offensive toy, Kevin O\'Connell.)', urgency: 'S, CB' },
  NE:  { coach: 'Mike Vrabel', scheme: '3-4',          storyline: 'Prioritize long-term roster health by investing in future starters along the line, at safety and at tight end. Draft a receiver to keep the heat on the Eagles.', urgency: 'OT, S' },
  NO:  { coach: 'Kellen Moore', scheme: '3-4',         storyline: 'Throw picks at receiver and defensive tackle.', urgency: 'WR, DT' },
  NYG: { coach: 'John Harbaugh', scheme: '3-4',        storyline: 'Plug right guard and find a replacement for Dexter Lawrence. Go "best player available" otherwise.', urgency: 'IOL, DT' },
  NYJ: { coach: 'Aaron Glenn', scheme: '4-3',          storyline: 'Pick several receivers while letting the defensive board come to you.', urgency: 'WR, LB' },
  PHI: { coach: 'Nick Sirianni', scheme: '3-4',        storyline: 'Weigh 2026 needs (safety, edge, WR) with big 2027 voids (offensive line, tight end) and try to split the difference.', urgency: 'S, EDGE' },
  PIT: { coach: 'Mike McCarthy', scheme: '3-4',        storyline: 'Get younger in the secondary and along the defensive line with multiple picks apiece. Get some sort of developmental quarterback on the roster.', urgency: 'S, DL' },
  SF:  { coach: 'Kyle Shanahan', scheme: '3-4',        storyline: 'Complete the defensive reload with another splashy edge rusher and a starting safety. Don\'t chase the flashy receiver when the meat-and-potatoes offensive lineman is there.', urgency: 'EDGE, S' },
  SEA: { coach: 'Mike Macdonald', scheme: '3-4',       storyline: 'Trade back unless great value on a safety or cornerback falls your way. Hit guard, edge and running back in the middle rounds.', urgency: 'S, CB' },
